using Android.App;\nusing Android.Content;\nusing Android.OS;\n\nnamespace CelesteAndroidTest \n{\n    [Activity(Label = "Celeste Launcher", MainLauncher = true)]\n    public class MainActivity : Activity \n    {\n        protected override void OnCreate(Bundle savedInstanceState) \n        {\n            base.OnCreate(savedInstanceState);\n            LaunchCeleste();\n        }\n\n        private void LaunchCeleste() \n        {\n            var activityClassName = "com.example.celeste.MainActivity"; // Replace with actual package name if different\n            var activityType = Java.Lang.Class.ForName(activityClassName);\n            var intent = new Intent(this, activityType);\n            StartActivity(intent);\n        }\n    }\n}